#!/bin/bash
TEAM_DB="${TEAM_DB:-team-db}"
$TEAM_DB "CREATE TABLE IF NOT EXISTS customers (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, stripe_customer_id TEXT, created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS phone_lines (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), customer_id TEXT NOT NULL REFERENCES customers(id), phone_number TEXT NOT NULL, twilio_number_sid TEXT, is_active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS call_logs (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), phone_line_id TEXT REFERENCES phone_lines(id), caller_number TEXT NOT NULL, call_sid TEXT, status TEXT NOT NULL DEFAULT 'missed', business_slug TEXT, created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS businesses (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), slug TEXT UNIQUE NOT NULL, name TEXT NOT NULL, access_code TEXT DEFAULT '1234', is_active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS chat_sessions (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), business_slug TEXT NOT NULL, caller_name TEXT, caller_number TEXT, status TEXT NOT NULL DEFAULT 'active', created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')), updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS chat_messages (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), session_id TEXT NOT NULL REFERENCES chat_sessions(id), role TEXT NOT NULL CHECK (role IN ('user','ai','system')), content TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
$TEAM_DB "CREATE TABLE IF NOT EXISTS leads (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), business_slug TEXT NOT NULL, name TEXT, phone TEXT, interest TEXT, notes TEXT, status TEXT NOT NULL DEFAULT 'new', created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')))"
echo "Database setup complete!"
